export function PageHeader({ variant = 'compact', children }: { variant?: 'hero' | 'compact'; children: React.ReactNode }) {
  const minH = { hero: 'clamp(20rem, 50vh, 32rem)', compact: 'clamp(4rem, 10vh, 6rem)' }[variant];
  return (
    <header style={{ minHeight: minH }} className="flex items-center px-4">
      {children}
    </header>
  );
}

